import React, { useEffect, useMemo, useState, useCallback } from 'react'
import { useAuth } from '../../context/AuthContext'
import { showToast } from '../../utils/toast'
import '../../styles/technician/technician-tasks.css'
import { taskService, pondService, productService, userService } from '../../services/api'

const STATUS_OPTIONS = [
  { value: 'ALL', label: 'Tất cả' },
  { value: 'PENDING', label: 'Chờ xử lý' },
  { value: 'IN_PROGRESS', label: 'Đang thực hiện' },
  { value: 'COMPLETED', label: 'Hoàn thành' },
]

const normalize = (v) => String(v || '').toUpperCase()

const TechnicianTasks = () => {
  const { user } = useAuth()

  // STATE
  const [tasks, setTasks] = useState([])
  const [ponds, setPonds] = useState([])
  const [products, setProducts] = useState([])
  const [workers, setWorkers] = useState([])

  const [loading, setLoading] = useState(false)

  const [search, setSearch] = useState('')
  const [statusFilter, setStatusFilter] = useState('ALL')

  const [selectedTask, setSelectedTask] = useState(null)
  const [isOpenCreate, setIsOpenCreate] = useState(false)

  const [form, setForm] = useState({
    task_type: '',
    pond_id: '',
    description: '',
    due_date: '',
    assigned_workers: [],
    product_id: '',
    quantity: 0,
  })

  // =====================
  // FETCHERS
  // =====================
  const fetchTasks = useCallback(async () => {
    try {
      setLoading(true)
      const res = await taskService.getAllTasks()
      setTasks(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải công việc', type: 'error' })
    } finally {
      setLoading(false)
    }
  }, [])

  const fetchPonds = useCallback(async () => {
    try {
      const res = await pondService.getAllPonds()
      setPonds(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải ao', type: 'error' })
    }
  }, [])

  const fetchProducts = useCallback(async () => {
    try {
      const res = await productService.getAllProducts()
      setProducts(res?.data?.data || [])
    } catch {
      showToast({ title: 'Không tải sản phẩm', type: 'error' })
    }
  }, [])

  const fetchWorkers = useCallback(async () => {
    try {
      const res = await userService.getWorkers()
      setWorkers(res?.data?.data || [])
    } catch (err) {
      console.error(err)
      showToast({ title: 'Không tải worker (có thể bị 403)', type: 'error' })
    }
  }, [])

  // INIT
  useEffect(() => {
    fetchTasks()
    fetchPonds()
    fetchProducts()
    fetchWorkers()
  }, [fetchTasks, fetchPonds, fetchProducts, fetchWorkers])

  // =====================
  // FILTER TASKS
  // =====================
  const filteredTasks = useMemo(() => {
    const s = search.toLowerCase()

    return tasks.filter(t => {
      const matchSearch =
        !s ||
        t.task_title?.toLowerCase().includes(s) ||
        t.pond_name?.toLowerCase().includes(s)

      const matchStatus =
        statusFilter === 'ALL' || normalize(t.status) === statusFilter

      return matchSearch && matchStatus
    })
  }, [tasks, search, statusFilter])

  // =====================
  // CREATE TASK
  // =====================
  const handleCreateTask = async () => {
    try {
      await taskService.createTask(form)

      showToast({ title: 'Tạo công việc thành công', type: 'success' })

      setIsOpenCreate(false)

      setForm({
        task_type: '',
        pond_id: '',
        description: '',
        due_date: '',
        assigned_workers: [],
        product_id: '',
        quantity: 0,
      })

      fetchTasks()
    } catch {
      showToast({ title: 'Tạo thất bại', type: 'error' })
    }
  }

  // =====================
  // STATUS UPDATE
  // =====================
  const handleStatusChange = async (taskId, status) => {
    try {
      await taskService.updateTaskStatus(taskId, status)
      showToast({ title: 'Cập nhật thành công', type: 'success' })
      fetchTasks()
    } catch {
      showToast({ title: 'Cập nhật thất bại', type: 'error' })
    }
  }

  // =====================
  // UI HELPERS
  // =====================
  const getStatusClass = (status) => {
    switch (normalize(status)) {
      case 'PENDING': return 'task-status task-status--pending'
      case 'IN_PROGRESS': return 'task-status task-status--progress'
      case 'COMPLETED': return 'task-status task-status--done'
      default: return 'task-status'
    }
  }

  const getStatusLabel = (status) => {
    switch (normalize(status)) {
      case 'PENDING': return 'Chờ xử lý'
      case 'IN_PROGRESS': return 'Đang xử lý'
      case 'COMPLETED': return 'Hoàn thành'
      default: return status
    }
  }

  // =====================
  // LOADING
  // =====================
  if (loading) {
    return (
      <div className="dashboard admin-page">
        <div className="flex-center table-loading-container">
          <div className="spinner" />
        </div>
      </div>
    )
  }

  // =====================
  // RENDER
  // =====================
  return (
    <div className="dashboard admin-page technician-tasks">

      {/* HEADER */}
      <div className="table-header">
        <div>
          <h2>Quản lý công việc</h2>
        </div>

        <button onClick={() => setIsOpenCreate(true)}>
          + Tạo công việc
        </button>
      </div>

      {/* FILTER */}
      <div className="table-toolbar">
        <input
          placeholder="Tìm kiếm..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
        />

        <select
          value={statusFilter}
          onChange={(e) => setStatusFilter(e.target.value)}
        >
          {STATUS_OPTIONS.map(o => (
            <option key={o.value} value={o.value}>
              {o.label}
            </option>
          ))}
        </select>
      </div>

      {/* TABLE */}
      <table className="table-base">
        <thead>
          <tr>
            <th>Công việc</th>
            <th>Ao</th>
            <th>Trạng thái</th>
            <th>Hành động</th>
          </tr>
        </thead>

        <tbody>
          {filteredTasks.map(task => (
            <tr key={task.task_id}>
              <td>{task.task_title}</td>
              <td>{task.pond_name}</td>

              <td>
                <span className={getStatusClass(task.status)}>
                  {getStatusLabel(task.status)}
                </span>
              </td>

              <td>
                <button onClick={() => setSelectedTask(task)}>
                  Chi tiết
                </button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>

      {/* DETAIL */}
      {selectedTask && (
        <div className="modal" onClick={() => setSelectedTask(null)}>
          <div className="modal-content" onClick={(e) => e.stopPropagation()}>
            <h3>Chi tiết</h3>

            <p>{selectedTask.task_title}</p>

            <select
              value={selectedTask.status}
              onChange={(e) =>
                handleStatusChange(selectedTask.task_id, e.target.value)
              }
            >
              <option value="PENDING">Chờ</option>
              <option value="IN_PROGRESS">Đang làm</option>
              <option value="COMPLETED">Xong</option>
            </select>

            <button onClick={() => setSelectedTask(null)}>
              Đóng
            </button>
          </div>
        </div>
      )}
    </div>
  )
}

export default TechnicianTasks
